I created a script to test the refactoring options. In the case that the user specifies duplicate keys, I think commitizen should raise an exception (`param` #3 below). If duplicates aren't cleaned from user input, sections would be repeated in the CHANGELOG. Additionally, all keys not in the commit history will need to be filtered after this sorting. I'll implement your suggestion and raise an exception on configuration errors

```py
"""Compare refactoring options."""

from typing import Callable, Iterable, List


def option_0(entry_keys: Iterable, change_type_order: List[str]) -> Iterable:
    """Variation of original implementation."""
    entry_change_types = sorted(entry_keys)
    ordered_change_types = []
    for ct in change_type_order + entry_change_types:
        # if ct in entry_change_types and ct not in ordered_change_types:
        if ct not in ordered_change_types:
            ordered_change_types.append(ct)
    return ordered_change_types


def option_1(entry_keys: Iterable, change_type_order: List[str]) -> Iterable:
    """Proposed alternative."""
    ordered_change_types = change_type_order + sorted(
        set(entry_keys) - set(change_type_order)
    )
    return ordered_change_types


def option_2(entry_keys: Iterable, change_type_order: List[str]) -> Iterable:
    change_types = change_type_order + sorted(entry_keys)
    return [ct for idx, ct in enumerate(change_types) if ct not in change_types[:idx]]


def test_option(func: Callable) -> None:
    param = [
        # Standard Use Case
        (['fix', 'feat', 'new'], ['new', 'fix'], ['new', 'fix', 'feat']),
        # No Overlap
        (['perf', 'fix', 'feat'], ['new', 'old'], ['new', 'old', 'feat', 'fix', 'perf']),
        # Duplicate in User-Specified
        (['perf', 'fix', 'feat'], ['new', 'alt', 'new'], ['new', 'alt', 'feat', 'fix', 'perf']),
    ]
    for idx, (entry_keys, change_type_order, expected) in enumerate(param):
        result = func(entry_keys, change_type_order)
        assert result == expected, '{} / {}'.format(param[idx], result)


if __name__ == '__main__':
    for func_name in [key for key in globals().keys() if key.startswith('option_')]:
        try:
            test_option(globals()[func_name])
        except AssertionError as error:
            print('Error on {}: {}'.format(func_name, error))
        else:
            print('Completed {}'.format(func_name))
```

