Oh, and for the sake of discussion, this is the alternative:

```
class StringPayload(BytesPayload):

    def __init__(self,
                 value: str,
                 *args: Any,
                 encoding: Optional[str]=None,
                 content_type: Optional[str]=None,
                 **kwargs: Any) -> None:
        _encoding, _content_type = self._parse_args(encoding, content_type)
        super().__init__(
            value.encode(_encoding),
            encoding=_encoding,
            content_type=_content_type,
            *args,
            **kwargs)

    @staticmethod
    def _parse_args(
        encoding: Optional[str]=None,
        content_type: Optional[str]=None,
    ) -> Tuple[str, str]:
        if encoding and content_type:
            return encoding, content_type
        elif encoding is None and content_type is None:
            return 'utf-8', 'text/plain; charset=utf-8'
        elif encoding is None and content_type:
            mimetype = parse_mimetype(content_type)
            return (
                mimetype.parameters.get('charset', 'utf-8'),
                content_type,
            )
        else:
            return (
                cast(str, encoding),
                'text/plain; charset=%s' % cast(str, encoding),
            )
```

Nit: Generally people recommend that only the code that throws the relevant exception should be inside of the `try: except:`, in this case `result = self.collection[self.index]` (This also cuts down on [`Hadouken code`](http://i.imgur.com/BtjZedW.jpg), as there will be 2 indentation levels instead of 3.)

```python
    def __next__(self):
        if self.step_back_once:
            self.index -= 1
            self.step_back_once = False 
            if self.index < 0:
                raise StopIteration
        else:
            self.index += 1

        try:
            result = self.collection[self.index]
        except IndexError:
            raise StopIteration

        return result
```

p.s. 'Nit' means nitpick, i.e. something that doesn't really matter that much.

