Let me post a example here:
```
import mxnet as mx


class MyMulMax(mx.operator.CustomOp):
    def __init__(self):
        super(MyMulMax, self).__init__()

    def forward(self, is_train, req, in_data, out_data, aux):
        a, b = in_data[0:2]
        c = mx.nd.batch_dot(a, b)
        d = mx.nd.max(c, axis=-1, keepdims=True)
        self.assign(out_data[0], req[0], d)

    def backward(self, req, out_grad, in_data, out_data, in_grad, aux):
        self.assign(in_grad[0], req[0], 0)
        self.assign(in_grad[1], req[1], 0)


@mx.operator.register("MyMulMax")
class MyMulMaxProp(mx.operator.CustomOpProp):
    def __init__(self):
        super(MyMulMaxProp, self).__init__()

    def list_arguments(self):
        return ['a', 'b']

    def list_outputs(self):
        return ['d']

    def infer_shape(self, in_shape):
        return in_shape, [list(in_shape[0][:-1] + [1])]

    def create_operator(self, ctx, shapes, dtypes):
        return MyMulMax()

def custom(n):
    with mx.Context(mx.gpu()):
        a = mx.nd.random.uniform(shape=(n, 600, 1))
        b = mx.nd.random.uniform(shape=(n, 1, 700))
        c = mx.nd.Custom(a, b, op_type="MyMulMax")
        # here c is outside ndarray, its duplicated ndarray is
        # out_data[0] in custom op with shared data,
        # their associated exception may not be synchronized
        # when OOM happens inside custom op
        c.wait_to_read()


if __name__ == "__main__":
    custom(100)
```

